import SideMenu from '@/components/SideMenu.vue'
import SideCart from '@/components/SideCart.vue'

export default {
  name: 'items',
  data () {
    return {
      href: this.$route.params.href,
      items: require('../items.json'),
      inventory: {
        id: 0,
        color: '',
        size: '',
        qty: 0
      }
    }
  },
  computed: {
    cartIsValid () {
      return this.inventory.color && this.inventory.size && this.inventory.qty
    }
  },
  components: {
    SideMenu,
    SideCart
  }
}
